import { sortBy } from 'lodash-es';

import { _OverlayTooltip as OverlayTooltip } from '@dynatrace/strato-components/charts';

import { useGeoLayerTooltip } from '../../hooks/use-geo-layer-tooltip.js';
import type { Location } from '../../types/location.js';
import type {
  BubbleLayerTooltipData,
  BubbleLayerTooltipHandler,
} from '../../types/tooltip.js';
import { isDefaultTooltipHandler } from '../../utils/tooltip-type-guards.js';

interface BubbleTooltipStatePayload {
  __color: string;
  __hoveredColor: string;
  __radius: number;
  __lat: number;
  data: Location;
}

export interface BubbleLayerTooltipProps {
  tooltipTemplate?: BubbleLayerTooltipHandler;
  hidden?: boolean;
  symbolAlignment?: 'left' | 'right';
}

export const BubbleLayerTooltip = (props: BubbleLayerTooltipProps) => {
  const { tooltipTemplate, hidden, symbolAlignment } = props;

  const { data, inBounds, position } =
    useGeoLayerTooltip<BubbleTooltipStatePayload>('geoBubble');

  if (hidden || !tooltipTemplate || !inBounds || !position) {
    return null;
  }

  if (!data || !data[0]) {
    return null;
  }

  const sanitizedData: BubbleLayerTooltipData[] = data.map((bubbleProps) => {
    const { __color: color, __radius: radius, data: customData } = bubbleProps;

    return {
      color,
      radius,
      data: customData,
    };
  });

  const sortedBubbles: BubbleLayerTooltipData[] = [
    ...sortBy(sanitizedData, ({ radius }) => radius),
  ];
  const closestPoint = sortedBubbles[0];
  const remainingPoints = sortedBubbles.slice(1);

  const template = closestPoint
    ? tooltipTemplate(closestPoint, remainingPoints)
    : null;

  if (!template) {
    return null;
  }

  if (isDefaultTooltipHandler(tooltipTemplate)) {
    return template;
  }

  return (
    <OverlayTooltip
      legacyTemplate={template}
      symbolAlignment={symbolAlignment}
    />
  );
};

BubbleLayerTooltip['displayName'] = 'BubbleLayerTooltip';
